local masterKey = iHiQrmYkIGGS._K[1]
local memSeed = iHiQrmYkIGGS._K[2]
local totalLen = iHiQrmYkIGGS._K[3]

local mappingTable = {}  
for i = 1, totalLen do mappingTable[i] = i end  
  
local current = memSeed  
local function lcgNext(min, max)  
    current = (current * 1103515245 + 12345) % 0x80000000  
    return min + (current % (max - min + 1))  
end  
  
for i = totalLen, 2, -1 do  
    local j = lcgNext(1, i)  
    mappingTable[i], mappingTable[j] = mappingTable[j], mappingTable[i]  
end  
  
local currentKey = masterKey  
local prevByte = 107  
local logicalIP = 1  
  
local STATE_ROUTER = 0xA1  
local STATE_RESOLVE = 0xB2  
local STATE_DECRYPT = 0xC3  
local STATE_TERMINATE = 0xF5  
local mState = STATE_ROUTER  
  
local targetPhysicalIndex = 0  
  
while mState ~= STATE_TERMINATE do  
    if mState == STATE_ROUTER then  
        if logicalIP > totalLen then  
